@app.post("/images", response_model=ImageCreateResponse)
async def upload_image(
    file: UploadFile = File(...),
    metadata_json: Optional[str] = Form(None),
    conn: sqlite3.Connection = Depends(db_dep),
):
    raw = await file.read()
    if not raw:
        raise HTTPException(status_code=400, detail="Empty file")
    try:
        Image.open(io.BytesIO(raw)).convert("RGB")
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image")

    image_id = str(uuid.uuid4())
    safe_name = os.path.basename(file.filename or f"{image_id}.jpg")
    ext = os.path.splitext(safe_name)[1].lower()
    if ext not in [".jpg", ".jpeg", ".png", ".bmp", ".webp"]:
        ext = ".jpg"
    filename = f"{image_id}{ext}"
    filepath = os.path.join(IMAGES_DIR, filename)

    with open(filepath, "wb") as f:
        f.write(raw)

    meta = {}
    if metadata_json:
        try:
            meta = json.loads(metadata_json)
            if not isinstance(meta, dict):
                meta = {"value": meta}
        except Exception:
            raise HTTPException(status_code=400, detail="metadata_json must be valid JSON")

    created_at = utcnow_iso()
    with _db_lock:
        cur = conn.cursor()
        cur.execute(
            "INSERT INTO images (id, filename, filepath, sha256, metadata_json, created_at) VALUES (?, ?, ?, ?, ?, ?)",
            (image_id, filename, filepath, sha256_bytes(raw), json.dumps(meta), created_at),
        )
        conn.commit()

    return ImageCreateResponse(image_id=image_id, filename=filename, created_at=created_at)


