@app.get("/images", response_model=ListImagesResponse)
def list_images(
    limit: int = 50,
    cursor: Optional[str] = None,
    conn: sqlite3.Connection = Depends(db_dep),
):
    limit = max(1, min(200, limit))
    cur = conn.cursor()

    if cursor:
        cur.execute(
            "SELECT * FROM images WHERE created_at < ? ORDER BY created_at DESC LIMIT ?",
            (cursor, limit + 1),
        )
    else:
        cur.execute("SELECT * FROM images ORDER BY created_at DESC LIMIT ?", (limit + 1,))

    rows = cur.fetchall()
    next_cursor = None
    if len(rows) > limit:
        next_cursor = rows[limit - 1]["created_at"]
        rows = rows[:limit]

    items: List[ImageInfoResponse] = []
    for r in rows:
        image_id = r["id"]
        cur.execute("SELECT COUNT(*) AS c FROM labels WHERE image_id = ?", (image_id,))
        num_labels = int(cur.fetchone()["c"])
        agg = get_aggregated_label(conn, image_id)
        counts = get_label_counts(conn, image_id)
        meta = {}
        if r["metadata_json"]:
            try:
                meta = json.loads(r["metadata_json"])
            except Exception:
                meta = {}
        items.append(
            ImageInfoResponse(
                image_id=image_id,
                filename=r["filename"],
                created_at=r["created_at"],
                metadata=meta,
                num_labels=num_labels,
                aggregated_label=agg,
                label_counts=counts,
            )
        )

    return ListImagesResponse(items=items, next_cursor=next_cursor)


@app.post("/labels", response_model=LabelUpsertResponse)
def upsert_label(req: LabelUpsertRequest, conn: sqlite3.Connection = Depends(db_dep)):
    with _db_lock:
        cur = conn.cursor()
        cur.execute("SELECT id FROM images WHERE id = ?", (req.image_id,))
