    cur.execute("SELECT COUNT(*) AS c FROM models")
    num_models = int(cur.fetchone()["c"])
    return {
        "num_images": num_images,
        "num_labels": num_labels,
        "num_models": num_models,
        "time": utcnow_iso(),
    }


